const now = new Date();
const h = String(now.getUTCHours()).padStart(2, '0');
const m = String(now.getUTCMinutes()).padStart(2, '0');
const checkTime = `${h}:${m}:00`;

// Only run between 17:00 and 21:00 UTC
const hour = now.getUTCHours();
if (hour < 17 || hour > 21) {
  console.log('Outside evening window, skipping');
  return [];
}

console.log('Checking for evening reminders at:', checkTime);
return [{ json: { checkTime } }];

const items = $input.first().json;

// Handle both array response and single-item
const prefs = Array.isArray(items) ? items : [items];

if (!prefs || prefs.length === 0 || !prefs[0].id) {
  console.log('No matching preferences found');
  return [];
}

console.log(`Found ${prefs.length} matching preference(s)`);

return prefs.map(p => ({ json: p }));

const pref = $('Split Preferences').item.json;
const sessions = $input.first().json;
const recentSession = Array.isArray(sessions) && sessions.length > 0 ? sessions[0] : null;

const childName = pref.child_profiles?.name || 'your child';
const subscription = pref.push_subscription;

if (!subscription || !subscription.endpoint) {
  console.log('No valid push subscription for child:', childName);
  return [];
}

let body;

if (recentSession) {
  const sessionDate = new Date(recentSession.created_at);
  const hoursSince = (Date.now() - sessionDate.getTime()) / (1000 * 60 * 60);

  if (hoursSince < 48 && recentSession.story_prompt) {
    const summary = recentSession.story_prompt.length > 50
      ? recentSession.story_prompt.substring(0, 50) + '...'
      : recentSession.story_prompt;
    body = `Time for tonight's story — last night ${childName} wanted "${summary}". What's on their mind tonight?`;
  } else {
    body = `Time to create tonight's story for ${childName} ✨`;
  }
} else {
  body = `Time to create tonight's story for ${childName} ✨`;
}

console.log('Sending evening reminder to:', childName);

return [{
  json: {
    subscription: subscription,
    payload: {
      title: 'DreamStation',
      body: body,
      tag: 'evening-reminder',
      url: '/?tab=create'
    }
  }
}];
